import React, {useEffect, useState} from 'react';
import {useSelector} from "react-redux";
import StatisticsTableProducts from "./StatistiscTableProducts";
import StatisticTableClients from "./StatustiscTableClients";
import {getInputElementDate, getOptions} from "../utility/input_element";
import {UNITS} from "../config/config_statistics";
import _ from "lodash";
import { CURRENCY } from '../config/config_products';
import Chart from "./Chart";

const Statistics = (props) => {
    const orders = useSelector(state => state.orders);
    const [ordersFilter, setOrderFilter] = useState([]);
    const [orderStatus, setOrderStatus] = useState("all orders");
    const [categoriesStatus, setCategoriesStatus] = useState("no");
    const [isInvalidFilterDates, setIsInvalidFilterDates] = useState(true);
    const [totalPriceAllOrders, setTotalPriceAllOrders] = useState(0);
    const [numberOfSales, setNumberOfSales] = useState(0);
    const [averageCheck, setAverageCheck] = useState(0);
    const [dateFrom, setDateFrom] = useState('');
    const [dateTo, setDateTo] = useState('');
    const [databaseProducts, setDatabaseProducts] = useState({});
    const [databaseClients, setDatabaseClients] = useState({});
    let formRef = null;

    const resetFilter = () => {
        setOrderFilter([]);
        setOrderStatus("all orders");
        setCategoriesStatus(false);
        setDateFrom('');
        setDateTo('');
        setTotalPriceAllOrders(0);
        setNumberOfSales(0);
        setAverageCheck(0);
        formRef.reset();
    }

    const handleChangeStatistics = (event) => {
        event.preventDefault();
        switch (event.target.name) {
            case "orderStatus":
                setOrderStatus(event.target.value);
                break;
            case "categories":
                setCategoriesStatus(event.target.value);
                break;
            default:
                break;
        }
    };

    const handleChangeDate = (event) => {
        event.preventDefault();
        console.log(event.target.value)
        switch (event.target.name) {
            case 'date-from':
                setDateFrom(event.target.value);
                break;
            case 'date-to':
                setDateTo(event.target.value);
                break;
            default:
                break;
        }
    }

    const onSubmit = (event) => {
        event.preventDefault();
        let tempTotalPrice = 0;
        let tempNumberOfSales = 0;
        let tempAverageCheck = 0;

        let temp = [...orders];
        if(!isInvalidFilterDates){
            tempTotalPrice = 0;
            tempNumberOfSales = 0;
            tempAverageCheck = 0;
            temp = _.filter(temp, order => {
                if(new Date(order.date).valueOf() >= new Date(dateFrom).valueOf() - 86400000  && new Date(order.date).valueOf() <= new Date(dateTo).valueOf()){
                    tempTotalPrice += order.totalPrice;
                    tempNumberOfSales++;
                    tempAverageCheck = tempTotalPrice/tempNumberOfSales;
                    return order;
                }
            })
        }
        if(orderStatus === "only paid"){
            tempTotalPrice = 0;
            tempNumberOfSales = 0;
            tempAverageCheck = 0;
            temp =  _.filter(temp, order => {
                if (order.isPaid) {
                    tempTotalPrice += order.totalPrice;
                    tempNumberOfSales++;
                    tempAverageCheck = tempTotalPrice/tempNumberOfSales;
                    return order;
                }
            })
        }
        if(orderStatus === "only not paid"){
            tempTotalPrice = 0;
            tempNumberOfSales = 0;
            tempAverageCheck = 0;
            temp =  _.filter(temp, order => {
                if (!order.isPaid) {
                    console.log(order.totalPrice)
                    tempTotalPrice += order.totalPrice;
                    tempNumberOfSales++;
                    tempAverageCheck = tempTotalPrice/tempNumberOfSales;
                    return order;
                }
            })
        }
        if(orderStatus === "all orders"){
            tempTotalPrice = 0;
            tempNumberOfSales = 0;
            tempAverageCheck = 0;
            temp.map(order => {
                tempTotalPrice += order.totalPrice;
                tempNumberOfSales++;
                tempAverageCheck = tempTotalPrice/tempNumberOfSales;
            });
        }
        setTotalPriceAllOrders(tempTotalPrice.toFixed(2));
        setNumberOfSales(tempNumberOfSales);
        setAverageCheck(tempAverageCheck.toFixed(2));
        setOrderFilter(temp);
    }

    // let arrayEntriesClients = [];
    // const getStatisticsOfClient = () => {
    //     let mapRes = new Map();
    //     props.orders.map(order => {
    //         if (!mapRes.has(order.username)) {
    //             mapRes.set(order.username, { count: 1, totalPurchases: Number(order.totalPrice) });
    //         } else {
    //             let property = mapRes.get(order.username);
    //             mapRes.set(order.username, { count: property.count + 1, totalPurchases: Number(property.totalPurchases) + Number(order.totalPrice) });
    //         }
    //     })
    //     return mapRes;
    // }
    // const maxVisitedOfClient = new Map([...getStatisticsOfClient().entries()].sort((a, b) => b[1].count - a[1].count));

    // let database = { labels: [], data: [], label: "customers statistic in a chart" }
    // for (let entry of maxVisitedOfClient) {
    //     arrayEntriesClients.push(entry);
    //     database.labels.push(entry[0]);
    //     database.data.push(entry[1].totalPurchases);
    // }

    // let arrayEntriesProducts = [];

    // const getStatisticsOfProduct = () => {
    //     let mapTemp = new Map();
    //     props.orders.map(order => {
    //         order.products.map(product => {
    //             if (props.categoriesStatus === "yes") {
    //                 if (!mapTemp.has(product.category)) {
    //                     mapTemp.set(product.category, { count: 1, quantity: product.quantity, unit: product.unit });
    //                 } else {
    //                     let property = mapTemp.get(product.category);
    //                     mapTemp.set(product.category, { count: property.count + 1, quantity: property.quantity + product.quantity, unit: property.unit });
    //                 }
    //             }
    //             else {
    //                 if (!mapTemp.has(product.name)) {
    //                     mapTemp.set(product.name, { count: 1, quantity: product.quantity, unit: product.unit });
    //                 } else {
    //                     let property = mapTemp.get(product.name);
    //                     mapTemp.set(product.name, { count: property.count + 1, quantity: property.quantity + product.quantity, unit: property.unit });
    //                 }
    //             }
    //         })
    //     })
    //     return mapTemp;
    // }
    // const maxSalesOfProduct = new Map([...getStatisticsOfProduct().entries()].sort((a, b) => b[1].count - a[1].count));

    // let database = { labels: [], data: [], label: label + " statistic in a chart" }
    // for (let entry of maxSalesOfProduct) {
    //     arrayEntriesProducts.push(entry);
    //     database.labels.push(entry[0]);
    //     database.data.push(entry[1].count);
    // }

    useEffect(() => {
        const isValidateFilterDates = () => {
            return dateFrom === '' || dateTo === '';
        };
        setIsInvalidFilterDates(isValidateFilterDates());
    }, [orderStatus, ordersFilter, dateFrom, dateTo])

    return <React.Fragment>
        <div className="content" >
            <div className="container">
                <div className="content-header">
                    <span className="title">- Statistics -</span>
                </div>
                <div className="content-body">
                    <div className="statistics-header">
                        <form  ref={(ref) => formRef = ref} onSubmit={onSubmit} noValidate>
                            <div className="statistics-properties_filter">
                                <div className="properties-filter_title">
                                    <span>Statistics by product category:</span>
                                </div>
                                <select className="filter-category" onChange={handleChangeStatistics} name="categories">
                                    {getOptions(["no", "yes"])}
                                </select>
                            </div>
                            <div className="statistics-properties_filter">
                                <div className="properties-filter_title">
                                    <span>Statistics by status orders:</span>
                                </div>
                                <select required className="filter-status_order" required onChange={handleChangeStatistics} name="orderStatus">
                                    {getOptions([...UNITS])}
                                </select>
                            </div>
                            <div className="statistics-properties_filter">
                                <div className="search-date_title">
                                    <span>Statistics by date:</span>
                                </div>
                                {getInputElementDate('input input-date', 'input-date_from', 'date', 'date-from', 'date-from', handleChangeDate, 'yyyy-mm-dd')}
                                <span>-</span>
                                {getInputElementDate('input input-date', 'input-date_to', 'date', 'date-to', 'date-to', handleChangeDate, 'yyyy-mm-dd')}
                                <button  className="button-submit button-submit_small " id="submit" type="submit">
                                    Submit
                                </button>
                            </div>
                        </form>
                    </div>
                    <div className="statistic-body">
                        <div className="statistics-properties">
                            <div className="statistics-properties_wrapper">
                                <span>Total orders:</span>
                                <div className="statistics-properties_content">{numberOfSales}</div>
                            </div>
                            <div className="statistics-properties_wrapper">
                                <span>Orders amount: {CURRENCY}</span>
                                <div className="statistics-properties_content">{totalPriceAllOrders}</div>
                            </div>
                            <div className="statistics-properties_wrapper">
                                <span>Average check: {CURRENCY}</span>
                                <div className="statistics-properties_content">{averageCheck}</div>
                            </div>
                        </div>
                        <div className="statistics-table">
                            <StatisticsTableProducts orders={ordersFilter} categoriesStatus={categoriesStatus}/>
                            <StatisticTableClients orders={ordersFilter}/>
                        </div>
                        <div className="statistics-charts">
                            <div className="chart-content_wrapper">
                                <Chart database={database} />
                            </div>
                            <div className="table-content_wrapper">
                                <Chart database={database} />
                            </div>
                        </div>
                        <div className="statistics-footer">
                            <button className="button-close button-close_small" onClick={resetFilter} id="submit" type="submit">
                                Reset
                        </button>
                        </div>
                    </div>
                </div>

            </div>
        </div>
    </React.Fragment>
}

export default Statistics;
